import functools

def memoize(func):
    cache = {}

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        # Create a hashable key from args and kwargs
        # args is a tuple, which is hashable.
        # kwargs (dictionary) is not directly hashable, so convert to frozenset of items.
        key = (args, frozenset(kwargs.items()))

        if key in cache:
            return cache[key]
        else:
            result = func(*args, **kwargs)
            cache[key] = result
            return result
    return wrapper
